  6→package kotlinx.datetime.internal.format.parser
  7→
  8→import kotlinx.datetime.internal.POWERS_OF_TEN
  9→import kotlinx.datetime.internal.DecimalFraction
 10→
 11→/**
 12→ * A parser that expects to receive a string consisting of [length] digits, or, if [length] is `null`,
 13→ * a string consisting of any number of digits.
 14→ */
 15→internal sealed class NumberConsumer<in Receiver>(
 16→    /** The number of digits to consume. `null` means that the length is variable. */
 17→    open val length: Int?,
 18→    /** The human-readable name of the entity being parsed here. */
 19→    val whatThisExpects: String
 20→) {
 21→    /**
 22→     * Wholly consumes the given [input]. Should be called with a string consisting of [length] digits, or,
 23→     * if [length] is `null`, with a string consisting of any number of digits. [consume] itself does not
 24→     * necessarily check the length of the input string, instead expecting to be passed a valid one.
 25→     *
 26→     * Returns `null` on success and a `NumberConsumptionError` on failure.
 27→     */
 28→    abstract fun consume(storage: Receiver, input: String): NumberConsumptionError?
 29→}
 30→
 31→internal interface NumberConsumptionError {
 32→    fun errorMessage(): String
 33→    object ExpectedInt: NumberConsumptionError {
 34→        override fun errorMessage() = "expected an Int value"
 35→    }
 36→    class TooManyDigits(val maxDigits: Int): NumberConsumptionError {
 37→        override fun errorMessage() = "expected at most $maxDigits digits"
 38→    }
 39→    class TooFewDigits(val minDigits: Int): NumberConsumptionError {
 40→        override fun errorMessage() = "expected at least $minDigits digits"
 41→    }
 42→    class WrongConstant(val expected: String): NumberConsumptionError {
 43→        override fun errorMessage() = "expected '$expected'"
 44→    }
 45→    class Conflicting(val conflicting: Any): NumberConsumptionError {
 46→        override fun errorMessage() = "attempted to overwrite the existing value '$conflicting'"
 47→    }
 48→}
 49→
 50→/**
 51→ * A parser that accepts an [Int] value in range from `0` to [Int.MAX_VALUE].
 52→ */
 53→// TODO: should the parser reject excessive padding?
 54→internal class UnsignedIntConsumer<in Receiver>(
 55→    private val minLength: Int?,
 56→    private val maxLength: Int?,
 57→    private val setter: AssignableField<Receiver, Int>,
 58→    name: String,
 59→    private val multiplyByMinus1: Boolean = false,
 60→) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
 61→
 62→    init {
 63→        require(length == null || length in 1..9) { "Invalid length for field $whatThisExpects: $length" }
 64→    }
 65→
 66→    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = when {
 67→        maxLength != null && input.length > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
 68→        minLength != null && input.length < minLength -> NumberConsumptionError.TooFewDigits(minLength)
 69→        else -> when (val result = input.toIntOrNull()) {
 70→            null -> NumberConsumptionError.ExpectedInt
 71→            else -> setter.setWithoutReassigning(storage, if (multiplyByMinus1) -result else result)
 72→        }
 73→    }
 74→}
 75→
 76→internal class ReducedIntConsumer<in Receiver>(
 77→    override val length: Int,
 78→    private val setter: AssignableField<Receiver, Int>,
 79→    name: String,
 80→    val base: Int,
 81→): NumberConsumer<Receiver>(length, name) {
 82→
 83→    private val modulo = POWERS_OF_TEN[length]
 84→    private val baseMod = base % modulo
 85→    private val baseFloor = base - baseMod
 86→
 87→    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = when (val result = input.toIntOrNull()) {
 88→        null -> NumberConsumptionError.ExpectedInt
 89→        else -> setter.setWithoutReassigning(storage, if (result >= baseMod) {
 90→            baseFloor + result
 91→        } else {
 92→            baseFloor + modulo + result
 93→        })
 94→    }
 95→}
 96→
 97→/**
 98→ * A parser that consumes exactly the string [expected].
 99→ */
100→internal class ConstantNumberConsumer<in Receiver>(
101→    private val expected: String
102→) : NumberConsumer<Receiver>(expected.length, "the predefined string $expected") {
103→    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = if (input == expected) {
104→        null
105→    } else {
106→        NumberConsumptionError.WrongConstant(expected)
107→    }
108→}
109→
110→internal class FractionPartConsumer<in Receiver>(
111→    private val minLength: Int?,
112→    private val maxLength: Int?,
113→    private val setter: AssignableField<Receiver, DecimalFraction>,
114→    name: String,
115→) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
116→    init {
117→        require(minLength == null || minLength in 1..9) { "Invalid length for field $whatThisExpects: $length" }
118→        // TODO: bounds on maxLength
119→    }
120→
121→    override fun consume(storage: Receiver, input: String): NumberConsumptionError? = when {
122→        minLength != null && input.length < minLength -> NumberConsumptionError.TooFewDigits(minLength)
123→        maxLength != null && input.length > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
124→        else -> when (val numerator = input.toIntOrNull()) {
125→            null -> NumberConsumptionError.TooManyDigits(9)
126→            else -> setter.setWithoutReassigning(storage, DecimalFraction(numerator, input.length))
127→        }
128→    }
129→}
130→
131→private fun <Object, Type> AssignableField<Object, Type>.setWithoutReassigning(
132→    receiver: Object,
133→    value: Type,
134→): NumberConsumptionError? {
135→    val conflictingValue = trySetWithoutReassigning(receiver, value) ?: return null
136→    return NumberConsumptionError.Conflicting(conflictingValue)
137→}
