package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Test that the parsing API only accepts ASCII digits (0-9) and rejects non-ASCII digits.
 * 
 * This test verifies the fix for the issue where non-ASCII digits like fullwidth digits (０-９)
 * and Arabic-Indic digits (٠-٩) were incorrectly accepted by the parser.
 */
class AsciiDigitParsingTest {

    @Test
    fun testRejectFullwidthDigits() {
        // Fullwidth digits (U+FF10 to U+FF19)
        LocalDate.Formats.ISO_BASIC.apply {
            // Should accept ASCII digits
            assertEquals(LocalDate(2024, 9, 6), parse("20240906"))

            // Should reject fullwidth digits
            assertCanNotParse("2０2４０９０６")  // Mix of ASCII and fullwidth
            assertCanNotParse("２０２４０９０６")  // All fullwidth
            assertCanNotParse("2024０９０６")     // Year in ASCII, rest in fullwidth
        }

        LocalDate.Formats.ISO.apply {
            // Should accept ASCII digits
            assertEquals(LocalDate(2024, 9, 6), parse("2024-09-06"))

            // Should reject fullwidth digits
            assertCanNotParse("２０２４-０９-０６")
            assertCanNotParse("2024-０９-０６")
        }
    }

    @Test
    fun testRejectArabicIndicDigits() {
        // Arabic-Indic digits (U+0660 to U+0669)
        LocalDate.Formats.ISO_BASIC.apply {
            // Should accept ASCII digits
            assertEquals(LocalDate(2024, 9, 6), parse("20240906"))

            // Should reject Arabic-Indic digits
            assertCanNotParse("2024٠٩٠٦")  // Year in ASCII, rest in Arabic-Indic
            assertCanNotParse("٢٠٢٤٠٩٠٦")  // All Arabic-Indic
        }

        LocalDate.Formats.ISO.apply {
            // Should accept ASCII digits
            assertEquals(LocalDate(2024, 9, 6), parse("2024-09-06"))

            // Should reject Arabic-Indic digits
            assertCanNotParse("2024-٠٩-٠٦")
            assertCanNotParse("٢٠٢٤-٠٩-٠٦")
        }
    }

    @Test
    fun testRejectDevanagariDigits() {
        // Devanagari digits (U+0966 to U+096F)
        LocalDate.Formats.ISO_BASIC.apply {
            // Should accept ASCII digits
            assertEquals(LocalDate(2024, 9, 6), parse("20240906"))

            // Should reject Devanagari digits
            assertCanNotParse("२०२४०९०६")  // All Devanagari
            assertCanNotParse("2024०९०६")  // Mix
        }
    }

    @Test
    fun testRejectNonAsciiDigitsInLocalTime() {
        LocalTime.Formats.ISO.apply {
            // Should accept ASCII digits
            assertEquals(LocalTime(14, 30, 0), parse("14:30:00"))

            // Should reject fullwidth digits
            assertCanNotParse("１４:３０:００")
            assertCanNotParse("14:３０:００")
        }
    }

    @Test
    fun testRejectNonAsciiDigitsInLocalDateTime() {
        LocalDateTime.Formats.ISO.apply {
            // Should accept ASCII digits
            assertEquals(LocalDateTime(2024, 9, 6, 14, 30, 0), parse("2024-09-06T14:30:00"))

            // Should reject fullwidth digits
            assertCanNotParse("２０２４-０９-０６T１４:３０:００")
            assertCanNotParse("2024-09-06T１４:３０:００")
        }
    }

    @Test
    fun testRejectNonAsciiDigitsInCustomFormat() {
        val format = LocalDate.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
        }

        // Should accept ASCII digits
        assertEquals(LocalDate(2024, 9, 6), format.parse("2024-09-06"))

        // Should reject fullwidth digits
        assertCanNotParse("２０２４-０９-０６", format)
        assertCanNotParse("2024-０９-06", format)
    }

    @Test
    fun testRejectNonAsciiDigitsInBasicFormat() {
        val format = LocalDate.Format {
            year()
            monthNumber()
            dayOfMonth()
        }

        // Should accept ASCII digits
        assertEquals(LocalDate(2024, 9, 6), format.parse("20240906"))

        // Should reject mixed ASCII and non-ASCII
        assertCanNotParse("2024０９０６", format)
        assertCanNotParse("202409０６", format)
    }

    private fun <T> assertCanNotParse(input: String, format: DateTimeFormat<T>) {
        val exception = assertFailsWith<DateTimeFormatException> { format.parse(input) }
        try {
            val message = exception.message ?: throw AssertionError("The parse exception didn't have a message")
            assertContains(message, input)
        } catch (e: AssertionError) {
            e.addSuppressed(exception)
            throw e
        }
    }
}
"}

