    try {
        val result = LocalDate.parse("20240906", LocalDate.Formats.ISO_BASIC)
        println("SUCCESS: Correctly parsed ASCII digits: $result")
        if (result == LocalDate(2024, 9, 6)) {
            println("SUCCESS: Result matches expected date")
        } else {
            println("FAIL: Result doesn't match expected date")
        }
    } catch (e: Exception) {
        println("FAIL: Failed to parse valid ASCII digits: ${e.message}")
    }
}
