fun main() {
    // Test the exact scenario from the issue
    try {
        val result = LocalDate.parse("2０2４٠٩０６", LocalDate.Formats.ISO_BASIC)
        println("FAIL: Parsed non-ASCII digits incorrectly: $result")
    } catch (e: Exception) {
        println("SUCCESS: Correctly rejected non-ASCII digits")
        println("Error message: ${e.message}")
